const raw = $input.first().json.body;
const data = typeof raw === 'string' ? JSON.parse(raw.replace(/^=\s*/, '').trim()) : raw;
return [{ json: data }];

const raw = $input.first().json.content[0].text;
let seoContent;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  seoContent = match ? JSON.parse(match[0]) : {};
} catch(e) {
  seoContent = { error: 'Error al parsear JSON', raw: raw };
}

const service = $('Parsear Body').first().json.service_name;
return [{ json: { seo_content: seoContent, generated_at: new Date().toISOString(), service: service } }];
